private Set createSetBasedOnExistingSet(Set original, List elements) {
    Set newSet;
    try {
        newSet = (Set) original.getClass().newInstance();
    } catch (Exception e) {
        newSet = new java.util.HashSet();
    }
    newSet.addAll(elements);
    return newSet;
}

