public void testSubListAdd() {
    List list = new ArrayList();
    List uniqueList = SetUniqueList.decorate(list);

    uniqueList.add("A");
    uniqueList.add("B");
    uniqueList.add("C");

    List subList = uniqueList.subList(1, 3);

    // Test that adding to sublist respects uniqueness within sublist
    assertTrue(subList.add("D"));
    assertTrue(subList.contains("D"));

    // Adding duplicate should fail
    assertFalse(subList.add("B"));
    assertEquals(3, subList.size());

    // Check parent list is updated
    assertEquals(4, uniqueList.size());
    assertTrue(uniqueList.contains("D"));
}

public void testSubListContainsAll() {
    List list = new ArrayList();
    List uniqueList = SetUniqueList.decorate(list);

    uniqueList.add("X");
    uniqueList.add("Y");
    uniqueList.add("Z");

    List subList = uniqueList.subList(0, 2);

    List checkList = new ArrayList();
    checkList.add("X");
    checkList.add("Y");
    assertTrue(subList.containsAll(checkList));

    checkList.add("Z");
    assertFalse(subList.containsAll(checkList));

    assertFalse(subList.contains("Z"));
}

public void testSubListWithTreeSet() {
    List list = new ArrayList();
    List uniqueList = new SetUniqueList307(list, new java.util.TreeSet());

    uniqueList.add("Apple");
    uniqueList.add("Banana");
    uniqueList.add("Cherry");

    List subList = uniqueList.subList(1, 2);

    assertTrue(subList.contains("Banana"));
    assertFalse(subList.contains("Apple"));
    assertFalse(subList.contains("Cherry"));

    // Test add with TreeSet backing
    assertTrue(subList.add("Date"));
    assertFalse(subList.add("Banana"));
}
